input.content:
"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Separator } from "@/components/ui/separator";
import { useAuth, type UserRole } from "@/lib/auth-context";
import {
  LayoutDashboard,
  Laptop,
  ClipboardPlus,
  Ticket,
  Bot,
  Bell,
  Settings,
  CheckSquare,
  BarChart3,
  Wrench,
  Package,
  Archive,
  Boxes,
  ClipboardList,
  Users,
  FileText,
  PieChart,
  Lightbulb,
  ChevronLeft,
  ChevronRight,
  type LucideIcon,
} from "lucide-react";

export type NavItem = {
  label: string;
  href: string;
  icon: LucideIcon;
  roles: UserRole[];
};

type NavSection = "main" | "work" | "manage" | "data";

const SECTION_LABELS: Record<NavSection, string | null> = {
  main: null,
  work: "工作",
  manage: "管理",
  data: "数据",
};

const navItems: (NavItem & { section: NavSection })[] = [
  // main section
  { label: "首页", href: "/home", icon: LayoutDashboard, roles: ["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"], section: "main" },
  { label: "AI 助手", href: "/chat", icon: Bot, roles: ["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"], section: "main" },
  { label: "通知中心", href: "/notifications", icon: Bell, roles: ["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"], section: "main" },
  // work section
  { label: "我的资产", href: "/my-assets", icon: Laptop, roles: ["EMPLOYEE", "MANAGER"], section: "work" },
  { label: "申领设备", href: "/apply", icon: ClipboardPlus, roles: ["EMPLOYEE", "MANAGER"], section: "work" },
  { label: "我的工单", href: "/tickets", icon: Ticket, roles: ["EMPLOYEE", "MANAGER"], section: "work" },
  { label: "审批工作台", href: "/approvals", icon: CheckSquare, roles: ["MANAGER"], section: "work" },
  // manage section
  { label: "IT 工作台", href: "/it/home", icon: Wrench, roles: ["IT_ADMIN"], section: "manage" },
  { label: "工单工作台", href: "/it/tickets", icon: Ticket, roles: ["IT_ADMIN"], section: "manage" },
  { label: "资产管理", href: "/it/assets", icon: Package, roles: ["IT_ADMIN"], section: "manage" },
  { label: "型号管理", href: "/it/models", icon: Archive, roles: ["IT_ADMIN"], section: "manage" },
  { label: "入库操作", href: "/it/inbound", icon: Boxes, roles: ["IT_ADMIN"], section: "manage" },
  { label: "盘点", href: "/it/inventory", icon: ClipboardList, roles: ["IT_ADMIN"], section: "manage" },
  { label: "用户管理", href: "/it/users", icon: Users, roles: ["IT_ADMIN"], section: "manage" },
  { label: "审计日志", href: "/it/audit", icon: FileText, roles: ["IT_ADMIN"], section: "manage" },
  // data section
  { label: "部门看板", href: "/dept-board", icon: BarChart3, roles: ["MANAGER"], section: "data" },
  { label: "资产大屏", href: "/exec/dashboard", icon: PieChart, roles: ["EXECUTIVE"], section: "data" },
  { label: "AI 洞察", href: "/exec/insights", icon: Lightbulb, roles: ["EXECUTIVE"], section: "data" },
  { label: "个人设置", href: "/profile", icon: Settings, roles: ["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"], section: "data" },
];

function filterNavItems(items: (NavItem & { section: NavSection })[], role: UserRole): (NavItem & { section: NavSection })[] {
  return items.filter((item) => item.roles.includes(role));
}

interface SidebarProps {
  collapsed?: boolean;
  onToggleCollapse?: () => void;
}

export function Sidebar({ collapsed = false, onToggleCollapse }: SidebarProps) {
  const pathname = usePathname();
  const { user, setRole } = useAuth();
  if (!user) return null;
  const filteredItems = filterNavItems(navItems, user.role);

  const allRoles: UserRole[] = ["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"];

  return (
    <div
      className={cn(
        "flex h-full flex-col bg-sidebar text-sidebar-foreground transition-all duration-200",
        collapsed ? "w-16" : "w-60",
      )}
    >
      {/* Brand area */}
      <div
        className={cn(
          "flex h-14 items-center border-b border-sidebar-border px-4",
          collapsed && "justify-center px-2",
        )}
      >
        {collapsed ? (
          <div className="flex size-8 items-center justify-center rounded-lg bg-linear-to-br from-primary to-primary/80 text-sidebar-primary-foreground text-xs font-bold">
            IT
          </div>
        ) : (
          <div className="flex items-center gap-2 overflow-hidden">
            <div className="flex size-8 shrink-0 items-center justify-center rounded-lg bg-linear-to-br from-primary to-primary/80 text-sidebar-primary-foreground text-xs font-bold">
              IT
            </div>
            <div className="min-w-0 flex-1">
              <div className="truncate text-sm font-semibold">资产管理系统</div>
              <div className="truncate text-xs text-sidebar-foreground/60">
                {user.department} · {user.name}
              </div>
            </div>
          </div>
        )}
      </div>

